import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import '../Css/Community.css';
import '../Css/Landing.css'; // Reuses header styles

const Community = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const username = location.state?.username || 'Gamer';

  const [posts, setPosts] = useState([]);
  const [newPost, setNewPost] = useState({ game_title: '', content: '', media_url: '', media_type: 'image' });

  // NEW: State to control what is shown in the center column
  const [activeTab, setActiveTab] = useState('feed'); // 'feed' or 'create'

  // Fetch real posts from backend
  const fetchPosts = async () => {
    try {
      const res = await fetch('http://localhost:8000/api/community/posts');
      const data = await res.json();
      if (data.status === 'success') {
        setPosts(data.posts);
      }
    } catch (err) {
      console.error("Failed to fetch posts", err);
    }
  };

  useEffect(() => { fetchPosts(); }, []);

  // Submit Post to PostgreSQL
  const handlePostSubmit = async () => {
    if (!newPost.media_url) return alert("Please add an image or video URL!");
    try {
      const payload = { ...newPost, username };
      const res = await fetch('http://localhost:8000/api/community/posts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await res.json();

      if (data.status === 'success') {
        setNewPost({ game_title: '', content: '', media_url: '', media_type: 'image' });
        fetchPosts(); 
        setActiveTab('feed'); // Switch back to the feed tab after posting!
      } else {
        alert("Failed to post: " + data.message);
      }
    } catch (err) { 
      alert("Network Error while posting."); 
    }
  };

  const soloChats = [
    { id: 1, name: 'AlexThePro', lastMsg: 'Are we playing tonight?', online: true },
    { id: 2, name: 'SarahHeals', lastMsg: 'Thanks for the carry!', online: false }
  ];
  const squadChats = [
    { id: 1, name: 'Elden Ring Tryhards', lastMsg: 'Need help with Malenia...' },
    { id: 2, name: 'CS2 Late Night', lastMsg: 'Queue up, we need 1 more.' }
  ];

  return (
    <div className="community-shield">
      {/* HEADER */}
      <header className="dash-header">
        <div className="logo" onClick={() => navigate('/landing', { state: { username } })}>GAMING<span>HUB</span></div>
        <nav className="dash-nav">
          <span onClick={() => navigate('/landing', { state: { username } })} style={{ cursor: 'pointer' }}>Home</span>
          <span className="active">The Nexus</span>
        </nav>
        <div className="profile-wrapper">
          <div className="avatar">{username.charAt(0).toUpperCase()}</div>
        </div>
      </header>

      <div className="community-layout">

        {/* ================= PILLAR 1: LEFT NAV ================= */}
        <aside className="comm-sidebar">
          <div className="comm-section-title">Main Hub</div>
          <div 
            className={`comm-menu-item ${activeTab === 'feed' ? 'active' : ''}`} 
            onClick={() => setActiveTab('feed')}
          >
            🌍 Nexus Feed
          </div>
          {/* NEW: Create Post Sidebar Button */}
          <div 
            className={`comm-menu-item ${activeTab === 'create' ? 'active' : ''}`} 
            onClick={() => setActiveTab('create')}
          >
            ✍️ Create Post
          </div>
          <div className="comm-menu-item">👤 My Profile</div>
          <div className="comm-menu-item">🔖 Saved Clips</div>

          <div className="comm-section-title" style={{marginTop: '30px'}}>Official Pages</div>
          <div className="comm-menu-item">⭐ Rockstar Games</div>
          <div className="comm-menu-item">⭐ CD Projekt Red</div>
          <div className="comm-menu-item">⭐ FromSoftware</div>
        </aside>

        {/* ================= PILLAR 2: CENTER PANEL ================= */}
        <main className="comm-feed">

          {/* CREATE POST TAB */}
          {activeTab === 'create' && (
            <div className="create-post-box">
              <h3 style={{marginTop: 0, marginBottom: '20px', color: '#fff'}}>Create Transmission</h3>
              <input 
                type="text" placeholder="What game are you playing?" 
                value={newPost.game_title} onChange={e => setNewPost({...newPost, game_title: e.target.value})}
              />
              <textarea 
                placeholder="Share a clip or drop a thought..." rows="3"
                value={newPost.content} onChange={e => setNewPost({...newPost, content: e.target.value})}
              />
              <div className="post-inputs-row">
                <input 
                  type="text" placeholder="Paste Image/Video URL here..." 
                  value={newPost.media_url} onChange={e => setNewPost({...newPost, media_url: e.target.value})}
                />
                <select value={newPost.media_type} onChange={e => setNewPost({...newPost, media_type: e.target.value})}>
                  <option value="image">Image</option>
                  <option value="video">Video (MP4)</option>
                </select>
              </div>
              <button className="post-btn" onClick={handlePostSubmit}>Transmit to Nexus</button>
              <div style={{ clear: 'both' }}></div>
            </div>
          )}

          {/* FEED TAB */}
          {activeTab === 'feed' && (
            <>
              {posts.length === 0 ? <div className="no-posts">No transmissions found. Be the first!</div> : null}
              {posts.map(post => (
                <div key={post.id} className="post-card">
                  <div className="post-header">
                    <span className="post-author">@{post.username}</span>
                    {post.game_title && <span className="post-game-tag">{post.game_title}</span>}
                  </div>

                  {post.media_type === 'video' ? (
                    <video src={post.media_url} controls className="post-media" />
                  ) : (
                    <img src={post.media_url} alt="Post media" className="post-media" onError={(e) => { e.target.src = "https://via.placeholder.com/800x400?text=Invalid+Image+URL"; }} />
                  )}

                  {post.content && <div className="post-content">{post.content}</div>}

                  <div className="post-actions">
                    <button className="action-btn gg-btn">🔺 GG ({post.gg_count || 0})</button>
                    <button className="action-btn">💬 Comments</button>
                  </div>
                </div>
              ))}
            </>
          )}
        </main>

        {/* ================= PILLAR 3: RIGHT COMMS ================= */}
        <aside className="comm-chat-panel">
          <div className="chat-half">
            <div className="chat-header">Direct Messages</div>
            <div className="chat-list">
              {soloChats.map(chat => (
                <div key={chat.id} className="chat-user">
                  <div className="chat-avatar">{chat.name.charAt(0)}</div>
                  <div className="chat-user-info">
                    <span>{chat.name} {chat.online && <div className="online-dot"></div>}</span>
                    <small>{chat.lastMsg}</small>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="chat-half">
            <div className="chat-header">My Squads</div>
            <div className="chat-list">
              {squadChats.map(chat => (
                <div key={chat.id} className="chat-user">
                  <div className="chat-avatar squad-icon">🛡️</div>
                  <div className="chat-user-info">
                    <span>{chat.name}</span>
                    <small>{chat.lastMsg}</small>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </aside>

      </div>
    </div>
  );
};

export default Community;
